def calculate_average(numbers):
    total = 0
    for n in numbers:
        total += n
    return total / len(numbers)  # Bug: crashes on empty list

print(calculate_average([]))

def is_prime(n):
    if n < 2:
        return False
    for i in range(2, int(n**0.5) + 1):
        if n % i == 0:
            return False
    return True

import json

def process_data(data):
    result = []
    for item in data:
        if item['status'] == 'active':
            result.append({'name': item['name'], 'score': item['value'] * 2})
    return result

def save_results(results, path):
    with open(path, 'w') as f:
        json.dump(results, f, indent=2)

def main():
    data = [
        {'name': 'Alice', 'status': 'active', 'value': 10},
        {'name': 'Bob', 'status': 'inactive', 'value': 20},
        {'name': 'Charlie', 'status': 'active', 'value': 30}
    ]
    results = process_data(data)
    save_results(results, 'output.json')

if __name__ == '__main__':
    main()
